export async function fetchAdminStats() {
  try {
    const [profiles, entries, history, recent] = await Promise.all([
      supabase.from('users').select('*', { count: 'exact', head: true }),
      supabase.from('lex_entries').select('*', { count: 'exact', head: true }),
